// import components
import home from "../views/home.vue";
import list from "../views/list.vue";
import product from "../views/product.vue";
import cart from "../views/cart.vue";
import login from "../views/login.vue";
import register from "../views/register.vue";
import checkout from "../views/checkout.vue";
import orders from "../views/orders.vue";
import profile from "../views/profile.vue";
import admin from "../views/admin.vue";
import dashboard from "../views/dashboard.vue";

const routers = [
  { path: '/', meta: { title: 'Super Mall' }, component: home },
  { path: '/list', meta: { title: 'All Products' }, component: list },
  { path: '/product/:id', meta: { title: 'Product Detail' }, component: product },
  { path: '/cart', meta: { title: '购物车' }, component: cart },
  { path: '/checkout', meta: { title: '确认订单' }, component: checkout },
  { path: '/orders', meta: { title: '我的订单' }, component: orders },
  { path: '/profile', meta: { title: '个人中心' }, component: profile },
  { path: '/dashboard', meta: { title: '数据仪表盘' }, component: dashboard },
  { path: '/admin', meta: { title: '图片管理' }, component: admin },
  { path: '/login', meta: { title: 'Login' }, component: login },
  { path: '/register', meta: { title: 'Register' }, component: register },
  { path: '*', redirect: '/' }
];
export default routers;
