<template>
  <div style="background: #f5f5f5; min-height: calc(100vh - 200px); display: flex; align-items: center; justify-content: center;">
    <div style="background: #fff; width: 400px; padding: 40px; border-radius: 8px; box-shadow: 0 2px 12px rgba(0,0,0,0.1);">
      <h2 style="text-align: center; margin-bottom: 32px; color: #333;">用户登录</h2>
      <div style="margin-bottom: 20px;">
        <label style="display: block; margin-bottom: 6px; color: #666; font-size: 14px;">用户名</label>
        <input v-model="userName" placeholder="请输入用户名" style="width: 100%; padding: 10px 12px; border: 1px solid #ddd; border-radius: 4px; font-size: 14px; box-sizing: border-box;" />
      </div>
      <div style="margin-bottom: 24px;">
        <label style="display: block; margin-bottom: 6px; color: #666; font-size: 14px;">密码</label>
        <input v-model="password" type="password" placeholder="请输入密码" @keyup.enter="handleLogin" style="width: 100%; padding: 10px 12px; border: 1px solid #ddd; border-radius: 4px; font-size: 14px; box-sizing: border-box;" />
      </div>
      <div v-if="errorMsg" style="color: #e4393c; font-size: 13px; margin-bottom: 16px;">{{ errorMsg }}</div>
      <button @click="handleLogin" style="width: 100%; padding: 12px; background: #ff5000; color: #fff; border: none; border-radius: 4px; font-size: 16px; cursor: pointer; font-weight: 600;">登录 </button>
      <div style="text-align: center; margin-top: 16px; font-size: 13px; color: #999;">
        还没有账号？<router-link to="/register" style="color: #ff5000;">立即注册</router-link>
      </div>
    </div>
  </div>
</template>

<script>
import axios from 'axios';
export default {
  data() { return { userName: '', password: '', errorMsg: '' }; },
  methods: {
    handleLogin() {
      if (!this.userName || !this.password) { this.errorMsg = '请输入用户名和密码'; return; }
      var param = new URLSearchParams();
      param.append('userName', this.userName);
      param.append('password', this.password);
      var self = this;
      axios.post('/eshop/user/login', param).then(function(res) {
        if (res.data.code === 200) {
          self.$store.commit('setUser', res.data.user);
          self.$store.commit('setRole', res.data.role || 'user');
          self.$store.commit('setToken', res.data.token);
          localStorage.setItem('token', res.data.token);
          localStorage.setItem('user', JSON.stringify(res.data.user));
          localStorage.setItem('role', res.data.role || 'user');
          self.$store.dispatch('fetchCartFromServer');
          self.$router.push('/');
        } else {
          self.errorMsg = res.data.msg || '登录失败';
        }
      }).catch(function() { self.errorMsg = '网络错误'; });
    }
  }
};
</script>
