<template>
  <div class="cart-page">
    <div class="section-title" style="margin:16px 0;">购物清单</div>
    <div class="cart-table" v-if="cartList.length">
      <div class="cart-table-header">
        <div class="cart-col-info">商品信息</div>
        <div class="cart-col-price">单价</div>
        <div class="cart-col-qty">数量</div>
        <div class="cart-col-total">小计</div>
        <div class="cart-col-action">操作</div>
      </div>
      <div class="cart-table-row" v-for="(item, index) in cartList" :key="index">
        <div class="cart-col-info">
          <img :src="dict[item.id] ? dict[item.id].pic : ''" style="width:80px;height:80px;object-fit:cover;border-radius:4px;border:1px solid #eee;" />
          <span>{{ dict[item.id] ? dict[item.id].name : '' }}</span>
        </div>
        <div class="cart-col-price">￥{{ dict[item.id] ? dict[item.id].price : 0 }}</div>
        <div class="cart-col-qty">
          <button class="cart-qty-btn" @click="changeCount(index, -1)">-</button>
          <span class="cart-qty-num">{{ item.count }}</span>
          <button class="cart-qty-btn" @click="changeCount(index, 1)">+</button>
        </div>
        <div class="cart-col-total">￥{{ dict[item.id] ? dict[item.id].price * item.count : 0 }}</div>
        <div class="cart-col-action"><span class="cart-delete-btn" @click="removeItem(index)">删除</span></div>
      </div>
    </div>
    <div class="cart-empty" v-else>
      购物车是空的，<router-link to="/list" style="color:#ff5000;">去逛逛</router-link>
    </div>
    <div class="cart-footer-bar" v-if="cartList.length">
      <span>共 <b>{{ countAll }}</b> 件</span>
      <span class="total-price">{{ costAll }}</span>
      <button class="cart-checkout-btn" @click="checkout">去结算</button>
    </div>
  </div>
</template>

<script>
export default {
  computed: {
    cartList() { return this.$store.state.cartList; },
    productList() { return this.$store.state.productList; },
    dict() {
      var d = {};
      this.productList.forEach(function(p) { d[p.id] = p; });
      return d;
    },
    countAll() { return this.cartList.reduce(function(s, i) { return s + i.count; }, 0); },
    costAll() {
      var self = this;
      return this.cartList.reduce(function(s, i) { return s + (self.dict[i.id] ? self.dict[i.id].price * i.count : 0); }, 0);
    }
  },
  methods: {
    changeCount(idx, n) { this.$store.commit('editCartCount', { id: this.cartList[idx].id, count: n }); },
    removeItem(idx) { this.$store.commit('deleteCart', this.cartList[idx].id); },
    checkout() {
      if (!this.$store.state.token) { this.$router.push('/login'); return; }
      this.$router.push('/checkout');
    }
  }
};
</script>
