import Vue from 'vue';
import VueRouter from 'vue-router';
import Routers from './router/index'; // 适配Vue CLI 4：路由文件为index.js
import Vuex from 'vuex';
import store from './store/index'; // 适配Vue CLI 4：Vuex单独存放
import App from './App.vue';
import './style.css';
import axios from 'axios';

Vue.use(VueRouter);
Vue.use(Vuex);
Vue.prototype.$axios = axios; // 全局挂载axios
Vue.config.productionTip = false;

// 路由配置
const RouterConfig = {
  mode: 'history',
  base: '/eshop/',
  routes: Routers
};
const router = new VueRouter(RouterConfig);

// 路由守卫：修改页面标题
router.beforeEach((to, from, next) => {
  window.document.title = to.meta.title;
  next();
});

// 路由切换滚动到顶部
router.afterEach(() => {
  window.scrollTo(0, 0);
});

// 创建Vue实例
new Vue({
  el: '#app',
  router: router,
  store: store,
  render: h => h(App)
});