<template>
  <div class="container" style="margin-top:16px;">
    <div class="list-toolbar">
      <span class="list-toolbar-label">Brand:</span>
      <div class="list-toolbar-items">
        <span class="list-toolbar-item" :class="{active: filterBrand === ''}" @click="filterBrand = ''">All</span>
        <span class="list-toolbar-item" v-for="b in brands" :key="b" :class="{active: filterBrand === b}" @click="setBrand(b)">{{ b }}</span>
      </div>
      <div class="list-toolbar-sort">
        <span :class="{active: order === ''}" @click="order = ''">Default</span>
        <span :class="{active: order.indexOf('price') > -1}" @click="togglePrice">
          Price {{ order === 'price-asc' ? '?' : order === 'price-desc' ? '?' : '' }}
        </span>
      </div>
    </div>
    <div v-if="keyword" style="background:#fff3eb;padding:12px 16px;border-radius:8px;margin-bottom:16px;color:#ff5000;">
      Search: "{{ keyword }}" ({{ filteredList.length }} results)
    </div>
    <div class="list-product-grid">
      <Product v-for="item in filteredList" :info="item" :key="item.id"></Product>
    </div>
    <div style="text-align:center;padding:40px;color:#999;" v-if="!filteredList.length">No products</div>

    <!-- Pagination -->
    <div v-if="!keyword && !filterCat && totalPages > 1" style="display:flex;justify-content:center;align-items:center;gap:8px;margin:24px 0;">
      <button @click="goPage(1)" :disabled="currentPage === 1" style="padding:6px 12px;border:1px solid #ddd;background:#fff;border-radius:4px;cursor:pointer;">首页</button>
      <button @click="goPage(currentPage - 1)" :disabled="currentPage === 1" style="padding:6px 12px;border:1px solid #ddd;background:#fff;border-radius:4px;cursor:pointer;">上一页</button>
      <span v-for="p in pageButtons" :key="p" @click="goPage(p)" :style="{padding:'6px 14px',border:'1px solid ' + (p === currentPage ? '#ff5000' : '#ddd'),background: p === currentPage ? '#ff5000' : '#fff',color: p === currentPage ? '#fff' : '#333',borderRadius:'4px',cursor:'pointer',fontWeight: p === currentPage ? '700' : '400'}">{{ p }}</span>
      <button @click="goPage(currentPage + 1)" :disabled="currentPage === totalPages" style="padding:6px 12px;border:1px solid #ddd;background:#fff;border-radius:4px;cursor:pointer;">下一页</button>
      <button @click="goPage(totalPages)" :disabled="currentPage === totalPages" style="padding:6px 12px;border:1px solid #ddd;background:#fff;border-radius:4px;cursor:pointer;">末页</button>
      <span style="color:#999;font-size:13px;">{{ totalItems }} items / {{ totalPages }} pages</span>
    </div>
  </div>
</template>

<script>
import Product from '../components/product.vue';
import axios from 'axios';

const CATEGORY_MAP = {
  '电脑': ['电脑', '笔记本', 'MacBook', 'ThinkPad', '联想', '华硕', 'Apple', 'Lenovo', 'ASUS', 'Dell', 'HP'],
  '手机': ['手机', 'iPhone', '华为', '小米', 'OPPO', 'vivo', 'Samsung'],
  '家电': ['冰箱', '电视', '空调', '洗衣机', '美的', '海尔', '海信', 'Midea', 'Haier', 'Hisense', 'Sony', '索尼', 'TCL'],
  '数码': ['相机', '耳机', '音箱', '平板', 'iPad'],
  '家居': ['沙发', '床', '桌子', '灯具', '窗帘'],
  '服饰': ['衣服', '鞋', '包', '手表', '首饰']
};

export default {
  components: { Product },
  data() {
    return {
      filterBrand: '', order: '', filterCat: '', keyword: '',
      searchResults: [],
      pageList: [],
      currentPage: 1,
      totalPages: 1,
      totalItems: 0,
      pageSize: 8
    };
  },
  computed: {
    list() {
      if (this.keyword) return this.searchResults;
      if (!this.filterCat && !this.filterBrand) return this.pageList;
      return this.$store.state.productList;
    },
    brands() { return this.$store.getters.brands; },
    filteredList() {
      var list = this.list.slice();
      if (this.filterCat) {
        var keywords = CATEGORY_MAP[this.filterCat] || [];
        var cat = this.filterCat;
        list = list.filter(function(item) {
          return keywords.some(function(kw) {
            return item.name.indexOf(kw) !== -1 || (item.brand && item.brand.indexOf(kw) !== -1);
          });
        });
      }
      if (this.filterBrand) {
        var fb = this.filterBrand;
        list = list.filter(function(item) { return item.brand === fb; });
      }
      if (this.order === 'price-asc') list.sort(function(a,b) { return a.price - b.price; });
      else if (this.order === 'price-desc') list.sort(function(a,b) { return b.price - a.price; });
      return list;
    },
    pageButtons() {
      var pages = [];
      var start = Math.max(1, this.currentPage - 2);
      var end = Math.min(this.totalPages, this.currentPage + 2);
      for (var i = start; i <= end; i++) pages.push(i);
      return pages;
    }
  },
  watch: {
    '$route.query.cat': {
      immediate: true,
      handler(val) { this.filterCat = val || ''; }
    },
    '$route.query.keyword': {
      immediate: true,
      handler(val) {
        this.keyword = val || '';
        if (val) this.doSearch(val);
        else if (!this.filterCat) this.loadPage(1);
      }
    }
  },
  methods: {
    setBrand(b) { this.filterBrand = this.filterBrand === b ? '' : b; },
    togglePrice() { this.order = this.order === 'price-desc' ? 'price-asc' : 'price-desc'; },
    doSearch(kw) {
      var self = this;
      axios.get('/eshop/product/search?keyword=' + encodeURIComponent(kw)).then(function(res) {
        self.searchResults = res.data;
      });
    },
    loadPage(page, retry) {
      if (!retry) retry = 0;
      var self = this;
      axios.get('/eshop/product/page?page=' + page + '&size=' + this.pageSize).then(function(res) {
        self.pageList = res.data.list;
        self.currentPage = res.data.page;
        self.totalPages = res.data.pages;
        self.totalItems = res.data.total;
      }).catch(function() {
        if (retry < 3) setTimeout(function() { self.loadPage(page, retry + 1); }, 1000);
      });
    },
    goPage(page) {
      if (page < 1 || page > this.totalPages) return;
      this.loadPage(page);
    }
  },
  mounted() {
    this.loadPage(1);
    if (!this.$store.state.productList.length) this.$store.dispatch('getProductList');
  }
};
</script>
