<template>
  <div class="container" style="margin-top:24px;">
    <div class="section-title">我的订单</div>
    <div v-if="!isLoggedIn" style="text-align:center;padding:60px;color:#999;">
      请先 <router-link to="/login" style="color:#ff5000;">登录</router-link>
    </div>
    <div v-else-if="loading" style="text-align:center;padding:60px;color:#999;">加载中...</div>
    <div v-else-if="orders.length === 0" style="text-align:center;padding:60px;color:#999;">
      暂无订单，<router-link to="/list" style="color:#ff5000;">去逛逛</router-link>
    </div>
    <div v-else>
      <div v-if="successMsg" style="background:#f6ffed;border:1px solid #b7eb8f;padding:12px 16px;border-radius:8px;margin-bottom:16px;color:#52c41a;">{{ successMsg }}</div>
      <div v-for="order in orders" :key="order.id" style="background:#fff;border-radius:8px;padding:20px 24px;margin-bottom:12px;box-shadow:0 1px 4px rgba(0,0,0,.08);">
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:12px;">
          <span style="color:#999;font-size:13px;">订单号：{{ order.id }} | {{ order.ordertime }}</span>
          <span :style="{color: statusColor(order.status), fontWeight:'700'}">{{ order.status }}</span>
        </div>
        <div style="display:flex;justify-content:space-between;align-items:center;">
          <span style="font-size:20px;font-weight:700;color:#ff5000;">{{ order.orderprice }}</span>
          <div style="display:flex;gap:8px;">
            <button v-if="order.status === '待付款'" @click="payOrder(order.id)" style="padding:6px 20px;background:#ff5000;color:#fff;border:none;border-radius:100px;cursor:pointer;">立即付款</button>
            <button v-if="order.status === '待付款'" @click="cancelOrder(order.id)" style="padding:6px 20px;background:#fff;color:#999;border:1px solid #ddd;border-radius:100px;cursor:pointer;">取消</button>
            <button v-if="order.status === '已付款'" @click="confirmOrder(order.id)" style="padding:6px 20px;background:#ff5000;color:#fff;border:none;border-radius:100px;cursor:pointer;">确认收货</button>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import axios from 'axios';
export default {
  data() { return { orders: [], loading: true, successMsg: '' }; },
  computed: {
    isLoggedIn() { return this.$store.state.token && this.$store.state.user; }
  },
  methods: {
    statusColor(status) {
      var map = { '待付款': '#faad14', '已付款': '#1890ff', '已完成': '#52c41a', '已取消': '#999' };
      return map[status] || '#999';
    },
    loadOrders() {
      var self = this;
      axios.get('/eshop/order/myOrders', { headers: { 'Authorization': this.$store.state.token } })
        .then(function(res) { self.orders = res.data.list || []; self.loading = false; });
    },
    payOrder(id) {
      var self = this;
      axios.post('/eshop/order/pay/' + id, null, { headers: { 'Authorization': this.$store.state.token } })
        .then(function() { self.loadOrders(); });
    },
    cancelOrder(id) {
      if (!confirm('确定取消订单？')) return;
      var self = this;
      axios.post('/eshop/order/cancel/' + id, null, { headers: { 'Authorization': this.$store.state.token } })
        .then(function() { self.loadOrders(); });
    },
    confirmOrder(id) {
      var self = this;
      axios.post('/eshop/order/confirm/' + id, null, { headers: { 'Authorization': this.$store.state.token } })
        .then(function() { self.loadOrders(); });
    }
  },
  mounted() {
    if (this.$route.query.msg) this.successMsg = this.$route.query.msg;
    if (this.isLoggedIn) this.loadOrders();
  }
};
</script>
