<template>
  <div class="container" style="margin-top:24px;">
    <div class="section-title">数据仪表盘</div>
    <div style="display:grid;grid-template-columns:repeat(auto-fill, minmax(200px, 1fr));gap:16px;margin-bottom:24px;">
      <div style="background:linear-gradient(135deg,#4f46e5,#7c3aed);color:#fff;border-radius:8px;padding:24px;">
        <div style="font-size:13px;opacity:.8;">商品总数</div>
        <div style="font-size:36px;font-weight:700;margin-top:8px;">{{ stats.products || 0 }}</div>
      </div>
      <div style="background:linear-gradient(135deg,#059669,#10b981);color:#fff;border-radius:8px;padding:24px;">
        <div style="font-size:13px;opacity:.8;">订单总数</div>
        <div style="font-size:36px;font-weight:700;margin-top:8px;">{{ stats.orders || 0 }}</div>
      </div>
      <div style="background:linear-gradient(135deg,#d97706,#f59e0b);color:#fff;border-radius:8px;padding:24px;">
        <div style="font-size:13px;opacity:.8;">用户总数</div>
        <div style="font-size:36px;font-weight:700;margin-top:8px;">{{ stats.users || 0 }}</div>
      </div>
      <div style="background:linear-gradient(135deg,#dc2626,#ef4444);color:#fff;border-radius:8px;padding:24px;">
        <div style="font-size:13px;opacity:.8;">成交金额</div>
        <div style="font-size:36px;font-weight:700;margin-top:8px;">{{ formatMoney(stats.revenue) }}</div>
      </div>
    </div>
    <!-- 快速入口 -->
    <div style="display:flex;gap:12px;flex-wrap:wrap;">
      <router-link to="/admin" style="padding:10px 20px;background:#fff;border:1px solid #eee;border-radius:6px;color:#4f46e5;text-decoration:none;font-size:13px;">图片管理</router-link>
      <router-link to="/orders" style="padding:10px 20px;background:#fff;border:1px solid #eee;border-radius:6px;color:#059669;text-decoration:none;font-size:13px;">我的订单</router-link>
      <router-link to="/profile" style="padding:10px 20px;background:#fff;border:1px solid #eee;border-radius:6px;color:#d97706;text-decoration:none;font-size:13px;">个人中心</router-link>
    </div>
  </div>
</template>

<script>
import axios from 'axios';
export default {
  data() { return { stats: {} }; },
  methods: {
    formatMoney(v) { return (v || 0).toFixed(2); },
    loadStats() {
      var self = this;
      axios.get('/eshop/admin/stats').then(function(res) { self.stats = res.data; });
    }
  },
  mounted() { this.loadStats(); }
};
</script>
