<template>
  <div class="container" style="margin-top:24px;">
    <div class="section-title">确认订单</div>
    <div v-if="!isLoggedIn" style="text-align:center;padding:60px;color:#999;">
      请先 <router-link to="/login" style="color:#ff5000;">登录</router-link> 后再下单
    </div>
    <div v-else-if="cartItems.length === 0" style="text-align:center;padding:60px;color:#999;">
      购物车为空，<router-link to="/list" style="color:#ff5000;">去逛逛</router-link>
    </div>
    <div v-else>
      <!-- 订单商品 -->
      <div style="background:#fff;border-radius:8px;padding:24px;margin-bottom:16px;box-shadow:0 1px 4px rgba(0,0,0,.08);">
        <table style="width:100%;border-collapse:collapse;">
          <tr style="border-bottom:1px solid #eee;color:#999;font-size:13px;">
            <th style="text-align:left;padding:12px 8px;">商品</th>
            <th style="padding:12px 8px;">单价</th>
            <th style="padding:12px 8px;">数量</th>
            <th style="padding:12px 8px;">小计</th>
          </tr>
          <tr v-for="item in cartItems" :key="item.id" style="border-bottom:1px solid #f5f5f5;">
            <td style="padding:12px 8px;display:flex;align-items:center;gap:12px;">
              <img :src="item.pic" style="width:60px;height:60px;object-fit:cover;border-radius:4px;" />
              <span>{{ item.name }}</span>
            </td>
            <td style="text-align:center;padding:12px 8px;">{{ item.price }}</td>
            <td style="text-align:center;padding:12px 8px;">{{ item.count }}</td>
            <td style="text-align:center;padding:12px 8px;color:#ff5000;font-weight:700;">{{ (item.price * item.count).toFixed(2) }}</td>
          </tr>
        </table>
      </div>
      <!-- 总计 -->
      <div style="background:#fff;border-radius:8px;padding:24px;margin-bottom:16px;box-shadow:0 1px 4px rgba(0,0,0,.08);display:flex;justify-content:flex-end;align-items:center;gap:24px;">
        <span style="color:#666;">共 {{ totalCount }} 件商品</span>
        <span style="font-size:24px;font-weight:700;color:#ff5000;">{{ totalPrice.toFixed(2) }}</span>
        <button @click="submitOrder" :disabled="submitting" style="padding:12px 48px;background:#ff5000;color:#fff;border:none;border-radius:100px;font-size:16px;font-weight:700;cursor:pointer;">
          {{ submitting ? '提交中...' : '提交订单' }}
        </button>
      </div>
    </div>
  </div>
</template>

<script>
import axios from 'axios';
export default {
  data() { return { submitting: false }; },
  computed: {
    isLoggedIn() { return this.$store.state.token && this.$store.state.user; },
    cartItems() {
      var self = this;
      return this.$store.state.cartList.map(function(item) {
        var product = self.$store.state.productList.find(function(p) { return p.id === item.id; });
        return { id: item.id, count: item.count, name: product ? product.name : '', price: product ? product.price : 0, pic: product ? product.pic : '' };
      }).filter(function(item) { return item.name; });
    },
    totalCount() { return this.cartItems.reduce(function(s, i) { return s + i.count; }, 0); },
    totalPrice() { return this.cartItems.reduce(function(s, i) { return s + i.price * i.count; }, 0); }
  },
  methods: {
    submitOrder() {
      var self = this;
      this.submitting = true;
      var cartData = this.$store.state.cartList.map(function(i) { return { id: i.id, count: i.count }; });
      var param = new URLSearchParams();
      param.append('cartJson', JSON.stringify(cartData));
      axios.post('/eshop/order/submit', param, {
        headers: { 'Authorization': this.$store.state.token }
      }).then(function(res) {
        self.submitting = false;
        if (res.data.code === 200) {
          self.$store.commit('emptyCart');
          self.$router.push('/orders?msg=下单成功');
        } else {
          alert(res.data.msg);
        }
      }).catch(function() { self.submitting = false; alert('网络错误'); });
    }
  },
  mounted() {
    if (!this.$store.state.productList.length) this.$store.dispatch('getProductList');
  }
};
</script>
