<template>
  <div class="container" style="margin-top:24px;">
    <div class="section-title">个人中心</div>
    <div v-if="!isLoggedIn" style="text-align:center;padding:60px;color:#999;">
      请先 <router-link to="/login" style="color:#ff5000;">登录</router-link>
    </div>
    <div v-else>
      <!-- 用户信息 -->
      <div style="background:#fff;border-radius:8px;padding:24px;margin-bottom:16px;box-shadow:0 1px 4px rgba(0,0,0,.08);">
        <h3 style="margin-bottom:16px;">基本信息</h3>
        <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;font-size:14px;color:#666;">
          <div>用户名：<b style="color:#333;">{{ user.userName }}</b></div>
          <div>姓名：<b style="color:#333;">{{ user.realName || '-' }}</b></div>
          <div>邮箱：<b style="color:#333;">{{ user.email || '-' }}</b></div>
          <div>注册时间：<b style="color:#333;">{{ user.regDate || '-' }}</b></div>
        </div>
      </div>

      <!-- Tab buttons -->
      <div style="display:flex;gap:0;margin-bottom:16px;">
        <button @click="tab='address'" :style="tabStyle('address')">收货地址</button>
        <button @click="tab='password'" :style="tabStyle('password')">修改密码</button>
        <button @click="tab='fav'" :style="tabStyle('fav')">我的收藏</button>
      </div>

      <!-- 地址管理 -->
      <div v-if="tab==='address'" style="background:#fff;border-radius:8px;padding:24px;box-shadow:0 1px 4px rgba(0,0,0,.08);">
        <div v-if="addresses.length">
          <div v-for="addr in addresses" :key="addr.id" style="border-bottom:1px solid #f5f5f5;padding:16px 0;display:flex;justify-content:space-between;align-items:center;">
            <div>
              <span style="font-weight:600;margin-right:12px;">{{ addr.receiver_name }}</span>
              <span style="color:#666;">{{ addr.receiver_phone }}</span>
              <span v-if="addr.is_default" style="background:#ff5000;color:#fff;font-size:11px;padding:1px 6px;border-radius:2px;margin-left:8px;">默认</span>
              <div style="color:#999;font-size:13px;margin-top:4px;">{{ addr.province }}{{ addr.city }}{{ addr.district }} {{ addr.detail_address }}</div>
            </div>
            <div style="display:flex;gap:8px;">
              <button v-if="!addr.is_default" @click="setDefault(addr.id)" style="padding:4px 12px;border:1px solid #ff5000;color:#ff5000;background:#fff;border-radius:4px;cursor:pointer;font-size:12px;">设为默认</button>
              <button @click="deleteAddr(addr.id)" style="padding:4px 12px;border:1px solid #ddd;color:#999;background:#fff;border-radius:4px;cursor:pointer;font-size:12px;">删除</button>
            </div>
          </div>
        </div>
        <div v-else style="text-align:center;padding:40px;color:#999;">暂无收货地址</div>

        <!-- 添加地址 -->
        <div style="margin-top:24px;padding-top:16px;border-top:1px solid #eee;">
          <h4 style="margin-bottom:12px;">{{ editingAddr ? '编辑地址' : '新增地址' }}</h4>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;">
            <div><input v-model="form.name" placeholder="收货人姓名" style="width:100%;padding:8px;border:1px solid #ddd;border-radius:4px;box-sizing:border-box;" /></div>
            <div><input v-model="form.phone" placeholder="手机号" style="width:100%;padding:8px;border:1px solid #ddd;border-radius:4px;box-sizing:border-box;" /></div>
            <div><input v-model="form.province" placeholder="省份" style="width:100%;padding:8px;border:1px solid #ddd;border-radius:4px;box-sizing:border-box;" /></div>
            <div><input v-model="form.city" placeholder="城市" style="width:100%;padding:8px;border:1px solid #ddd;border-radius:4px;box-sizing:border-box;" /></div>
            <div><input v-model="form.district" placeholder="区/县" style="width:100%;padding:8px;border:1px solid #ddd;border-radius:4px;box-sizing:border-box;" /></div>
            <div style="display:flex;align-items:center;gap:12px;">
              <label style="font-size:13px;color:#666;white-space:nowrap;"><input type="checkbox" v-model="form.isDefault" /> 设为默认</label>
            </div>
          </div>
          <div style="margin-top:12px;"><input v-model="form.detail" placeholder="详细地址（街道/门牌号）" style="width:100%;padding:8px;border:1px solid #ddd;border-radius:4px;box-sizing:border-box;" /></div>
          <div v-if="addrMsg" style="margin-top:8px;font-size:13px;" :style="{color: addrOk ? '#52c41a' : '#e4393c'}">{{ addrMsg }}</div>
          <button @click="addAddress" style="margin-top:12px;padding:8px 32px;background:#ff5000;color:#fff;border:none;border-radius:4px;cursor:pointer;">保存地址</button>
        </div>
      </div>

      <!-- 修改密码 -->
      <div v-if="tab==='password'" style="background:#fff;border-radius:8px;padding:24px;box-shadow:0 1px 4px rgba(0,0,0,.08);">
        <div style="max-width:400px;">
          <div style="margin-bottom:16px;"><label style="display:block;margin-bottom:6px;color:#666;">原密码</label><input v-model="pwd.old" type="password" style="width:100%;padding:10px;border:1px solid #ddd;border-radius:4px;box-sizing:border-box;" /></div>
          <div style="margin-bottom:16px;"><label style="display:block;margin-bottom:6px;color:#666;">新密码</label><input v-model="pwd.new1" type="password" style="width:100%;padding:10px;border:1px solid #ddd;border-radius:4px;box-sizing:border-box;" /></div>
          <div style="margin-bottom:16px;"><label style="display:block;margin-bottom:6px;color:#666;">确认新密码</label><input v-model="pwd.new2" type="password" style="width:100%;padding:10px;border:1px solid #ddd;border-radius:4px;box-sizing:border-box;" /></div>
          <div v-if="pwdMsg" style="margin-bottom:12px;font-size:13px;" :style="{color: pwdOk ? '#52c41a' : '#e4393c'}">{{ pwdMsg }}</div>
          <button @click="changePwd" style="padding:10px 48px;background:#ff5000;color:#fff;border:none;border-radius:4px;cursor:pointer;">确认修改</button>
        </div>
      </div>
    
      <div v-if="tab==='fav'" style="background:#fff;border-radius:8px;padding:24px;box-shadow:0 1px 4px rgba(0,0,0,.08);">
        <div v-if="favorites.length">
          <div v-for="fav in favorites" :key="fav.id" style="display:flex;align-items:center;gap:16px;padding:12px 0;border-bottom:1px solid #f5f5f5;">
            <img :src="fav.pic" style="width:60px;height:60px;object-fit:cover;border-radius:4px;" />
            <div style="flex:1;">
              <router-link :to="'/product/' + fav.pid" style="color:#333;font-weight:500;">{{ fav.name }}</router-link>
              <div style="color:#ff5000;font-weight:700;margin-top:4px;">{{ fav.price }}</div>
            </div>
            <button @click="removeFav(fav.pid)" style="padding:4px 12px;border:1px solid #ddd;color:#999;background:#fff;border-radius:4px;cursor:pointer;font-size:12px;">取消收藏</button>
          </div>
        </div>
        <div v-else style="text-align:center;padding:40px;color:#999;">暂无收藏</div>
      </div>

    </div>
  </div>
</template>

<script>
import axios from 'axios';
export default {
  data() {
    return {
      tab: 'address',
      addresses: [],
      form: { name: '', phone: '', province: '', city: '', district: '', detail: '', isDefault: false },
      editingAddr: false, addrMsg: '', addrOk: false,
      pwd: { old: '', new1: '', new2: '' }, pwdMsg: '', pwdOk: false, favorites: []
    };
  },
  computed: {
    isLoggedIn() { return this.$store.state.token && this.$store.state.user; },
    user() { return this.$store.state.user || {}; }
  },
  methods: {
    tabStyle(t) { return { padding: '10px 24px', border: 'none', background: this.tab === t ? '#ff5000' : '#f5f5f5', color: this.tab === t ? '#fff' : '#666', cursor: 'pointer', fontSize: '14px', borderRadius: '4px 4px 0 0', marginRight: '4px' }; },
    loadAddresses() {
      var self = this;
      axios.get('/eshop/address/list', { headers: { 'Authorization': this.$store.state.token } })
        .then(function(res) { self.addresses = res.data.list || []; });
    },
    addAddress() {
      if (!this.form.name || !this.form.phone || !this.form.detail) { this.addrMsg = '请填写必填项'; this.addrOk = false; return; }
      var self = this;
      var p = new URLSearchParams();
      p.append('receiverName', this.form.name);
      p.append('receiverPhone', this.form.phone);
      p.append('province', this.form.province || '');
      p.append('city', this.form.city || '');
      p.append('district', this.form.district || '');
      p.append('detailAddress', this.form.detail);
      p.append('isDefault', this.form.isDefault ? 1 : 0);
      axios.post('/eshop/address/add', p, { headers: { 'Authorization': this.$store.state.token } })
        .then(function(res) {
          if (res.data.code === 200) {
            self.addrMsg = '添加成功'; self.addrOk = true;
            self.form = { name: '', phone: '', province: '', city: '', district: '', detail: '', isDefault: false };
            self.loadAddresses();
          }
        });
    },
    deleteAddr(id) {
      if (!confirm('确定删除？')) return;
      var self = this;
      axios.post('/eshop/address/delete/' + id, null, { headers: { 'Authorization': this.$store.state.token } })
        .then(function() { self.loadAddresses(); });
    },
    setDefault(id) {
      var self = this;
      axios.post('/eshop/address/setDefault/' + id, null, { headers: { 'Authorization': this.$store.state.token } })
        .then(function() { self.loadAddresses(); });
    },
    loadFavorites() {
      var self = this;
      axios.get('/eshop/favorite/list', { headers: { 'Authorization': this.$store.state.token } })
        .then(function(res) { self.favorites = res.data.list || []; });
    },
    removeFav(pid) {
      var self = this;
      var p = new URLSearchParams(); p.append('productId', pid);
      axios.post('/eshop/favorite/remove', p, { headers: { 'Authorization': this.$store.state.token } })
        .then(function() { self.loadFavorites(); });
    },
    changePwd() {
      if (!this.pwd.old || !this.pwd.new1) { this.pwdMsg = '请填写密码'; this.pwdOk = false; return; }
      if (this.pwd.new1 !== this.pwd.new2) { this.pwdMsg = '两次新密码不一致'; this.pwdOk = false; return; }
      var self = this;
      var p = new URLSearchParams();
      p.append('oldPwd', this.pwd.old);
      p.append('newPwd', this.pwd.new1);
      axios.post('/eshop/user/changePwd', p, { headers: { 'Authorization': this.$store.state.token } })
        .then(function(res) {
          if (res.data.code === 200) { self.pwdMsg = '修改成功'; self.pwdOk = true; self.pwd = { old: '', new1: '', new2: '' }; }
          else { self.pwdMsg = res.data.msg; self.pwdOk = false; }
        });
    }
  },
  mounted() {
    if (this.isLoggedIn) { this.loadAddresses(); this.loadFavorites(); }
  }
};
</script>
