<template>
  <div style="background: #f5f5f5; min-height: calc(100vh - 200px); display: flex; align-items: center; justify-content: center;">
    <div style="background: #fff; width: 400px; padding: 40px; border-radius: 8px; box-shadow: 0 2px 12px rgba(0,0,0,0.1);">
      <h2 style="text-align: center; margin-bottom: 32px; color: #333;">用户注册</h2>
      <div style="margin-bottom: 16px;"><label style="display: block; margin-bottom: 6px; color: #666; font-size: 14px;">用户名</label>
        <input v-model="userName" placeholder="请输入用户名" style="width: 100%; padding: 10px 12px; border: 1px solid #ddd; border-radius: 4px; font-size: 14px; box-sizing: border-box;" /></div>
      <div style="margin-bottom: 16px;"><label style="display: block; margin-bottom: 6px; color: #666; font-size: 14px;">密码</label>
        <input v-model="password" type="password" placeholder="请输入密码" style="width: 100%; padding: 10px 12px; border: 1px solid #ddd; border-radius: 4px; font-size: 14px; box-sizing: border-box;" /></div>
      <div style="margin-bottom: 16px;"><label style="display: block; margin-bottom: 6px; color: #666; font-size: 14px;">姓名</label>
        <input v-model="realName" placeholder="请输入姓名" style="width: 100%; padding: 10px 12px; border: 1px solid #ddd; border-radius: 4px; font-size: 14px; box-sizing: border-box;" /></div>
      <div style="margin-bottom: 16px;"><label style="display: block; margin-bottom: 6px; color: #666; font-size: 14px;">邮箱</label>
        <input v-model="email" placeholder="请输入邮箱" style="width: 100%; padding: 10px 12px; border: 1px solid #ddd; border-radius: 4px; font-size: 14px; box-sizing: border-box;" /></div>
      <div v-if="errorMsg" style="color: #e4393c; font-size: 13px; margin-bottom: 12px;">{{ errorMsg }}</div>
      <div v-if="successMsg" style="color: #52c41a; font-size: 13px; margin-bottom: 12px;">{{ successMsg }}</div>
      <button @click="handleRegister" style="width: 100%; padding: 12px; background: #ff5000; color: #fff; border: none; border-radius: 4px; font-size: 16px; cursor: pointer; font-weight: 600;">注 册</button>
      <div style="text-align: center; margin-top: 16px; font-size: 13px; color: #999;">已有账号？<router-link to="/login" style="color: #ff5000;">立即登录</router-link></div>
    </div>
  </div>
</template>

<script>
import axios from 'axios';
export default {
  data() { return { userName: '', password: '', realName: '', email: '', errorMsg: '', successMsg: '' }; },
  methods: {
    handleRegister() {
      if (!this.userName || !this.password) { this.errorMsg = '用户名和密码不能为空'; return; }
      var param = new URLSearchParams();
      param.append('userName', this.userName);
      param.append('password', this.password);
      param.append('realName', this.realName);
      param.append('email', this.email);
      var self = this;
      axios.post('/eshop/user/register', param).then(function(res) {
        if (res.data.code === 200) {
          self.successMsg = '注册成功';
          setTimeout(function() { self.$router.push('/login'); }, 1500);
        } else { self.errorMsg = res.data.msg; }
      }).catch(function() { self.errorMsg = '网络错误'; });
    }
  }
};
</script>
