<template>
  <div class="container" v-if="product">
    <div class="detail-wrap">
      <div class="detail-image">
        <img :src="product.pic" :alt="product.name" style="max-width:100%;max-height:100%;object-fit:contain;" />
      </div>
      <div class="detail-info">
        <h1 class="detail-name">{{ product.name }}</h1>
        <p class="detail-desc">{{ product.intro }}</p>
        <div class="detail-price-box">
          <div class="detail-price-label">价格</div>
          <div class="detail-price-value">{{ product.price }}</div>
        </div>
        <div class="detail-actions">
          <button class="btn-outline" @click="toggleFavorite" :style="{color: favorited ? '#e4393c' : '#ff5000', borderColor: favorited ? '#e4393c' : '#ff5000'}">{{ favorited ? '已收藏' : '收藏' }}</button>
          <button class="btn-primary" @click="addToCart">加入购物车</button>
          <button class="btn-outline" @click="goBuy">立即购买</button>
        </div>
      </div>
    </div>
    <div class="detail-desc-section">
      <div class="section-title">商品详情</div>
      <p style="line-height:2;color:#666;">{{ product.intro }}</p>
    </div>

    <!-- 评价区 -->
    <div class="detail-desc-section">
      <div class="section-title">用户评价 ({{ reviews.length }})</div>
      <!-- 发表评价 -->
      <div v-if="isLoggedIn" style="margin-bottom:24px;padding:16px;background:#fafafa;border-radius:8px;">
        <div style="display:flex;align-items:center;gap:12px;margin-bottom:12px;">
          <span style="font-size:13px;color:#666;">评分：</span>
          <span v-for="s in 5" :key="s" @click="myRating = s" style="font-size:24px;cursor:pointer;" :style="{color: s <= myRating ? '#faad14' : '#ddd'}">&#9733;</span>
        </div>
        <textarea v-model="myComment" placeholder="写下你的评价..." style="width:100%;height:80px;padding:10px;border:1px solid #ddd;border-radius:4px;resize:vertical;box-sizing:border-box;"></textarea>
        <div style="display:flex;justify-content:space-between;align-items:center;margin-top:8px;">
          <label style="font-size:13px;color:#999;"><input type="checkbox" v-model="myAnonymous" /> 匿名评价</label>
          <button @click="submitReview" style="padding:8px 24px;background:#ff5000;color:#fff;border:none;border-radius:4px;cursor:pointer;">发表评价</button>
        </div>
        <div v-if="reviewMsg" style="margin-top:8px;font-size:13px;color:#52c41a;">{{ reviewMsg }}</div>
      </div>
      <div v-else style="margin-bottom:16px;color:#999;font-size:13px;">
        <router-link to="/login" style="color:#ff5000;">登录</router-link> 后可以发表评价
      </div>
      <!-- 评价列表 -->
      <div v-if="reviews.length">
        <div v-for="rv in reviews" :key="rv.id" style="border-bottom:1px solid #f5f5f5;padding:16px 0;">
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:6px;">
            <span style="font-weight:600;font-size:14px;">{{ rv.is_anonymous ? '匿名用户' : (rv.realName || rv.userName || '用户') }}</span>
            <span style="color:#faad14;">{{ '\u2605'.repeat(rv.rating) }}{{ '\u2606'.repeat(5 - rv.rating) }}</span>
            <span style="color:#999;font-size:12px;margin-left:auto;">{{ rv.created_time }}</span>
          </div>
          <div style="color:#666;font-size:14px;line-height:1.8;">{{ rv.comment }}</div>
        </div>
      </div>
      <div v-else style="text-align:center;padding:30px;color:#999;">暂无评价，成为第一个评价的人吧</div>
    </div>

    <!-- 相关推荐 -->
    <div class="detail-desc-section">
      <div class="section-title">相关推荐</div>
      <div class="product-grid">
        <router-link v-for="item in related" :key="item.id" :to="'/product/' + item.id" class="product-card">
          <img :src="item.pic" class="product-card-image" :alt="item.name" />
          <div class="product-card-body">
            <div class="product-card-title">{{ item.name }}</div>
            <div class="product-card-price">{{ item.price }}</div>
          </div>
        </router-link>
      </div>
    </div>
  </div>
</template>

<script>
import axios from 'axios';
export default {
  data() {
    return {
      product: null,
      reviews: [],
      myRating: 5, myComment: '', myAnonymous: false, reviewMsg: '', favorited: false
    };
  },
  computed: {
    id() { return parseInt(this.$route.params.id); },
    isLoggedIn() { return this.$store.state.token && this.$store.state.user; },
    related() {
      return this.$store.state.productList.filter(function(p) { return p.id !== this.id; }.bind(this)).slice(0, 5);
    }
  },
  methods: {
    getProduct() {
      var self = this;
      axios.get('/eshop/product/getProductById/' + this.id).then(function(res) { self.product = res.data;
            self.product.pic = 'http://localhost:8080/eshop/product_images/' + self.product.pic; });
    },
    loadReviews() {
      var self = this;
      axios.get('/eshop/review/list/' + this.id).then(function(res) { self.reviews = res.data.list || []; });
    },
    addToCart() { this.$store.commit('addCart', this.id); alert('已加入购物车！'); },
    toggleFavorite() {
      if (!this.isLoggedIn) { this.$router.push('/login'); return; }
      var self = this;
      var url = this.favorited ? '/eshop/favorite/remove' : '/eshop/favorite/add';
      var p = new URLSearchParams(); p.append('productId', this.id);
      axios.post(url, p, { headers: { 'Authorization': this.$store.state.token } }).then(function() {
        self.favorited = !self.favorited;
      });
    },
    checkFavorite() {
      if (!this.isLoggedIn) return;
      var self = this;
      axios.get('/eshop/favorite/check/' + this.id, { headers: { 'Authorization': this.$store.state.token } })
        .then(function(res) { self.favorited = res.data.favorited; });
    },
    goBuy() { this.$router.push('/cart'); },
    submitReview() {
      if (!this.myComment.trim()) return alert('请输入评价内容');
      var self = this;
      var p = new URLSearchParams();
      p.append('productId', this.id);
      p.append('rating', this.myRating);
      p.append('comment', this.myComment);
      p.append('anonymous', this.myAnonymous ? 1 : 0);
      axios.post('/eshop/review/add', p, { headers: { 'Authorization': this.$store.state.token } })
        .then(function(res) {
          if (res.data.code === 200) {
            self.reviewMsg = '评价成功！';
            self.myComment = ''; self.myRating = 5; self.myAnonymous = false;
            self.loadReviews();
          }
        });
    }
  },
  mounted() {
    this.getProduct();
    this.loadReviews();
    this.checkFavorite();
    if (!this.$store.state.productList.length) this.$store.dispatch('getProductList');
  }
};
</script>
