<template>
  <div class="container" style="margin-top:24px;">
    <div class="section-title">商品图片管理</div>
    <div style="background:#fff;border-radius:8px;padding:24px;box-shadow:0 1px 4px rgba(0,0,0,.08);">
      <div style="display:grid;grid-template-columns:repeat(auto-fill, minmax(200px, 1fr));gap:16px;">
        <div v-for="p in products" :key="p.id" style="border:1px solid #eee;border-radius:8px;padding:12px;text-align:center;">
          <img :src="p.pic" style="width:100%;height:150px;object-fit:cover;border-radius:4px;margin-bottom:8px;" />
          <div style="font-size:13px;font-weight:500;margin-bottom:8px;">#{{ p.id }} {{ p.name }}</div>
          <input type="file" :id="'fu' + p.id" accept="image/*" style="width:100%;font-size:11px;" />
          <button @click="uploadFor(p)" style="margin-top:6px;width:100%;padding:6px;background:#ff5000;color:#fff;border:none;border-radius:4px;cursor:pointer;font-size:12px;">上传并更新</button>
          <div v-if="msgs[p.id]" style="color:#52c41a;font-size:11px;margin-top:4px;">{{ msgs[p.id] }}</div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import axios from 'axios';
export default {
  data() { return { products: [], msgs: {} }; },
  methods: {
    uploadFor(p) {
      var el = document.getElementById('fu' + p.id);
      var file = el.files[0];
      if (!file) return;
      var self = this;
      var fd = new FormData();
      fd.append('file', file);
      fd.append('productId', p.id);
      axios.post('/eshop/admin/uploadForProduct', fd).then(function(res) {
        if (res.data.code === 200) {
          self.msgs[p.id] = '已更新';
          p.pic = '/product_images/' + res.data.pic + '?t=' + Date.now();
          el.value = '';
          setTimeout(function() { self.msgs[p.id] = ''; }, 2000);
        }
      });
    },
    loadProducts() {
      var self = this;
      axios.get('/eshop/product/getProduct').then(function(res) {
        res.data.forEach(function(p) { p.pic = 'http://localhost:8080/eshop/product_images/' + p.pic; });
        self.products = res.data;
      });('/eshop/product/getProduct').then(function(res) { self.products = res.data; });
    }
  },
  mounted() { this.loadProducts(); }
};
</script>
