import Vue from 'vue';
import Vuex from 'vuex';
import axios from 'axios';

Vue.use(Vuex);

function getFilterArray(array) {
  var res = [];
  var json = {};
  for (var i = 0; i < array.length; i++) {
    var s = array[i];
    if (!json[s]) { res.push(s); json[s] = 1; }
  }
  return res;
}

// Load saved state from localStorage
var savedToken = localStorage.getItem('token') || '';
var savedUser = null;
try { savedUser = JSON.parse(localStorage.getItem('user')); } catch(e) {}

// Load cart from localStorage
var savedCart = [];
try { savedCart = JSON.parse(localStorage.getItem('cart')) || []; } catch(e) {}

function saveCartToLocal(cart) {
  localStorage.setItem('cart', JSON.stringify(cart));
}

var store = new Vuex.Store({
  state: {
    productList: [],
    cartList: savedCart,
    user: savedUser,
    token: savedToken,
    role: localStorage.getItem('role') || ''
  },
  getters: {
    brands: function(state) {
      return getFilterArray(state.productList.map(function(item) { return item.brand; }));
    },
    isLoggedIn: function(state) {
      return state.token && state.user;
    }
  },
  mutations: {
    setProductList(state, data) { state.productList = data; },
    setUser(state, user) { state.user = user; },
    setToken(state, token) { state.token = token; },
    setUser(state, user) { state.user = user; },
    setRole(state, role) { state.role = role; },
    setCartList(state, list) { state.cartList = list; saveCartToLocal(list); },
    logout(state) {
      state.user = null; state.token = ''; state.cartList = [];
      localStorage.removeItem('token'); localStorage.removeItem('user');
      localStorage.removeItem('role'); localStorage.removeItem('cart');
    },
    addCart(state, id) {
      var item = state.cartList.find(function(i) { return i.id === id; });
      if (item) { item.count++; }
      else { state.cartList.push({ id: id, count: 1 }); }
      saveCartToLocal(state.cartList);
      // Sync to server if logged in
      if (state.token) {
        axios.post('/eshop/cart/add?productId=' + id + '&quantity=1', null, {
          headers: { 'Authorization': state.token }
        });
      }
    },
    editCartCount(state, payload) {
      var item = state.cartList.find(function(i) { return i.id === payload.id; });
      if (item) {
        item.count += payload.count;
        if (item.count <= 0) { item.count = 1; }
      }
      saveCartToLocal(state.cartList);
      if (state.token && item) {
        axios.post('/eshop/cart/update?productId=' + payload.id + '&quantity=' + item.count, null, {
          headers: { 'Authorization': state.token }
        });
      }
    },
    deleteCart(state, id) {
      var idx = state.cartList.findIndex(function(i) { return i.id === id; });
      if (idx >= 0) { state.cartList.splice(idx, 1); }
      saveCartToLocal(state.cartList);
      if (state.token) {
        axios.post('/eshop/cart/remove?productId=' + id, null, {
          headers: { 'Authorization': state.token }
        });
      }
    },
    emptyCart(state) {
      state.cartList = [];
      saveCartToLocal([]);
      if (state.token) {
        axios.post('/eshop/cart/clear', null, {
          headers: { 'Authorization': state.token }
        });
      }
    }
  },
  actions: {
    getProductList(context) {
      axios.get('/eshop/product/getProduct').then(function(result) {
        var list = result.data;
        if (list && list.length) {
          list.forEach(function(p) { p.pic = 'http://localhost:8080/eshop/product_images/' + p.pic; });
        }
        context.commit('setProductList', list);
      });
    },
    // Fetch cart from server and merge with local
    fetchCartFromServer(context) {
      if (!context.state.token) return;
      var self = this;
      axios.get('/eshop/cart/list', { headers: { 'Authorization': context.state.token } })
        .then(function(res) {
          var serverCart = res.data.map(function(item) {
            return { id: item.pid, count: item.quantity };
          });
          // Merge local cart into server cart
          var localCart = context.state.cartList;
          var merged = serverCart.slice();
          localCart.forEach(function(localItem) {
            var exists = merged.find(function(s) { return s.id === localItem.id; });
            if (exists) {
              exists.count = Math.max(exists.count, localItem.count);
            } else {
              merged.push(localItem);
            }
          });
          context.commit('setCartList', merged);
          // Sync merged cart back to server
          merged.forEach(function(item) {
            axios.post('/eshop/cart/add?productId=' + item.id + '&quantity=' + item.count, null, {
              headers: { 'Authorization': context.state.token }
            });
          });
          // Clear merged items from server that aren't in merged
          serverCart.forEach(function(sItem) {
            var stillExists = merged.find(function(m) { return m.id === sItem.id; });
            if (stillExists) {
              axios.post('/eshop/cart/update?productId=' + sItem.id + '&quantity=' + stillExists.count, null, {
                headers: { 'Authorization': context.state.token }
              });
            }
          });
        });
    }
  }
});

export default store;
