<template>
  <div>
    <!-- Hero Banner -->
    <div class="hero-banner">
      <div class="hero-main" @click="$router.push('/list')">
        <div class="hero-main-content">
          <h1>优选好物 品质生活</h1>
          <p>精选好货 / 天天低价 / 正品保障</p>
          <span class="hero-btn">立即选购</span>
        </div>
      </div>
      <div class="hero-side">
        <div class="hero-side-item" @click="$router.push('/list')">
          <h3>新品首发</h3>
          <span>iPhone 15 Pro</span>
        </div>
        <div class="hero-side-item" @click="$router.push('/list')">
          <h3>超值家电</h3>
          <span>冰箱空调低至5折</span>
        </div>
      </div>
    </div>

    <div class="container" style="margin-top:24px;">
      <!-- 分类图标 -->
      <div class="page-section">
        <div class="section-title">商品分类</div>
        <div class="category-grid">
          <div class="category-item" v-for="cat in categories" :key="cat.name" @click="$router.push('/list')">
            <div class="category-icon" :style="{background: cat.color}">{{ cat.icon }}</div>
            <div class="category-name">{{ cat.name }}</div>
          </div>
        </div>
      </div>

      <!-- 热门推荐 -->
      <div class="page-section">
        <div class="section-title">热门推荐</div>
        <div class="product-grid">
          <router-link
            v-for="item in hotProducts"
            :key="item.id"
            :to="'/product/' + item.id"
            class="product-card animate-fade-in-up"
          >
            <img :src="item.pic" class="product-card-image" :alt="item.name" />
            <div class="product-card-body">
              <div class="product-card-title">{{ item.name }}</div>
              <div class="product-card-price">{{ item.price }}</div>
            </div>
            <span class="product-card-tag" v-if="item.tag">{{ item.tag }}</span>
          </router-link>
        </div>
      </div>

      <!-- 新品上架 -->
      <div class="page-section">
        <div class="section-title" style="border-color:#e4393c;color:#e4393c;">新品上架</div>
        <div class="product-grid">
          <router-link
            v-for="item in flashSale"
            :key="item.id"
            :to="'/product/' + item.id"
            class="product-card animate-fade-in-up"
          >
            <img :src="item.pic" class="product-card-image" :alt="item.name" />
            <div class="product-card-body">
              <div class="product-card-title">{{ item.name }}</div>
              <div class="product-card-price" style="color:#e4393c;">{{ item.price }}</div>
            </div>
            <span class="product-card-tag">{{ item.tag }}</span>
          </router-link>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return {
      categories: [
        { name: '笔记本电脑', icon: '💻', color: '#e8f4fd' },
        { name: '手机', icon: '💿', color: '#fce4ec' },
        { name: '平板', icon: '💨', color: '#f3e5f5' },
        { name: '冰箱', icon: '🤏', color: '#e0f2f1' },
        { name: '电视', icon: '💆', color: '#fff3e0' },
        { name: '空调', icon: '🐈', color: '#e8eaf6' },
        { name: '洗衣机', icon: '🨠', color: '#e0f7fa' },
        { name: '厨房电器', icon: '🕴', color: '#fff8e1' },
        { name: '数码配件', icon: '📴', color: '#f1f8e9' },
        { name: '更多分类', icon: '🔃', color: '#efebe9' }
      ]
    }
  },
  computed: {
    hotProducts() {
      return this.$store.state.productList.slice(0, 5).map((p, i) => ({
        ...p,
        emoji: ['💆', '💅', '💤', '💠', '💉'][i],
        tag: i === 0 ? '爆款' : ''
      }))
    },
    flashSale() {
      return this.$store.state.productList.slice(5, 10).map((p, i) => ({
        ...p,
        emoji: ['🎠', '🎢', '🔰', '🌬', '🙀'][i],
        tag: '-' + (30 + i * 10) + '%'
      }))
    }
  },
  mounted() {
    if (!this.$store.state.productList.length) {
      this.$store.dispatch('getProductList')
    }
  }
}
</script>
