<template>
  <div>
    <!-- 顶部小黑条 -->
    <div class="header-top">
      <div class="header-top-inner">
        <span>欢迎来到超帅电商</span>
        <div>
          <router-link to="/dashboard" v-if="isAdmin">仪表盘</router-link>
          <router-link to="/profile">个人中心</router-link>
          <router-link to="/orders">我的订单</router-link>
          <a href="http://localhost:8081/ecpbm/admin_login.jsp" target="_blank" v-if="isAdmin">后台管理</a>
        </div>
      </div>
    </div>

    <!-- 主头部 -->
    <div class="header">
      <div class="header-main">
        <router-link to="/" class="header-logo">优选商城<span></span></router-link>
        <div class="header-search">
          <input v-model="keyword" placeholder="搜索你想要的商品" @keyup.enter="handleSearch" />
          <button @click="handleSearch">搜索</button>
        </div>
        <div class="header-actions">
          <template v-if="isLoggedIn">
            <span style="color:#666;font-size:13px;">{{ userName }}</span>
            <a href="javascript:void(0)" @click="doLogout" style="color:#999;font-size:13px;">退出</a>
          </template>
          <router-link to="/login" v-else style="color:#666;font-size:13px;">登录</router-link>
          <router-link to="/register" v-if="!isLoggedIn" style="color:#666;font-size:13px;">注册</router-link>
          <router-link to="/cart" class="cart-link">
            购物车
            <span class="cart-badge" v-if="cartCount">{{ cartCount }}</span>
          </router-link>
        </div>
      </div>
    </div>

    <!-- 分类导航条 -->
    <div class="nav-bar">
      <div class="nav-bar-inner">
        <router-link to="/" exact-active-class="active">首页</router-link>
        <router-link to="/list" active-class="active">全部商品</router-link>
        <router-link to="/list?cat=电脑">电脑</router-link>
        <router-link to="/list?cat=手机">手机</router-link>
        <router-link to="/list?cat=家电">家电</router-link>
        <router-link to="/list?cat=数码">数码</router-link>
        <router-link to="/list?cat=家居">家居</router-link>
        <router-link to="/list?cat=服饰">服饰</router-link>
      </div>
    </div>

    <!-- 页面内容 -->
    <router-view />

    <!-- 页脚 -->
    <div class="footer">
      <div class="footer-inner">
        <div class="footer-col">
          <h4>商品分类</h4>
          <router-link to="/list?cat=电脑">电脑</router-link>
          <router-link to="/list?cat=手机">手机</router-link>
          <router-link to="/list?cat=家电">家用电器</router-link>
          <router-link to="/list?cat=数码">数码配件</router-link>
        </div>
        <div class="footer-col">
          <h4>快捷入口</h4>
          <router-link to="/list">全部商品</router-link>
          <router-link to="/cart">购物车</router-link>
          <router-link to="/login">用户登录</router-link>
          <router-link to="/register">免费注册</router-link>
        </div>
        <div class="footer-col">
          <h4>客户服务</h4>
          <a href="javascript:void(0)" @click="toggleInfo('help')">帮助中心</a>
          <a href="javascript:void(0)" @click="toggleInfo('after')">售后服务</a>
          <a href="javascript:void(0)" @click="toggleInfo('contact')">在线客服</a>
        </div>
        <div class="footer-col">
          <h4>关于我们</h4>
          <a href="javascript:void(0)" @click="toggleInfo('about')">公司简介</a>
          <a href="javascript:void(0)" @click="toggleInfo('addr')">联系方式</a>
          <a href="http://localhost:8081/ecpbm/admin_login.jsp" target="_blank" v-if="isAdmin">后台管理</a>
        </div>
      </div>
      <div v-if="showInfo" class="footer-info" style="max-width:1200px;margin:0 auto 16px;padding:16px 24px;background:rgba(255,255,255,0.05);border-radius:8px;color:#aaa;font-size:13px;line-height:2;">
    <div v-if="showInfo==='help'">
      <strong style="color:#fff;">帮助中心</strong><br>
      购物流程：选择商品 → 加入购物车 → 结算下单。<br>
      支付方式：目前支持在线支付（模拟），下单即完成。
    </div>
    <div v-if="showInfo==='after'">
      <strong style="color:#fff;">售后服务</strong><br>
      支持7天无理由退换货，质量问题15天内包换。<br>
      退换货请联系客服，提供订单号即可处理。
    </div>
    <div v-if="showInfo==='contact'">
      <strong style="color:#fff;">在线客服</strong><br>
      客服热线：400-888-8888<br>
      客服邮箱：service@youxuanshop.com<br>
      工作时间：周一至周日 9:00 - 21:00
    </div>
    <div v-if="showInfo==='about'">
      <strong style="color:#fff;">公司简介</strong><br>
      优选商城成立于2026年，致力于为消费者提供优质商品和便捷的购物体验。<br>
      主营笔记本电脑、手机、家用电器等品类，正品保障，售后无忧。
    </div>
    <div v-if="showInfo==='addr'">
      <strong style="color:#fff;">联系方式</strong><br>
      公司地址：广东省深圳市南山区科技园<br>
      联系电话：0755-88888888<br>
      商务合作：biz@youxuanshop.com
    </div>
  </div>
  <div class="footer-bottom" style="max-width:1200px;margin:0 auto;padding:0 16px;">
        &copy; 2026 优选商城 - All Rights Reserved
      </div>
    </div>
  </div>
</template>

<script>
export default {
  data() {
    return { keyword: '', showInfo: '' }
  },
  computed: {
    cartCount() {
      return this.$store.state.cartList.length
    },
    isLoggedIn() {
      return this.$store.state.token && this.$store.state.user;
    },
    isAdmin() {
      return localStorage.getItem('role') === 'admin';
    },
    userName() {
      return this.$store.state.user ? this.$store.state.user.userName || this.$store.state.user.realName : ""
    }
  },
  methods: {
    doLogout() {
      this.$store.commit("logout")
      this.$router.push("/")
    },
    toggleInfo(type) { this.showInfo = this.showInfo === type ? '' : type; },
    handleSearch() {
      if (this.keyword.trim()) {
        this.$router.push('/list?keyword=' + encodeURIComponent(this.keyword))
      }
    }
  }
}
</script>
